import React, { useState, useEffect, useRef } from "react";
import "./App.css";

function App() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [place, setPlace] = useState(""); // NEW STATE
  const chatEndRef = useRef(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = async () => {
    if (!input) return;

    const userText = input.toLowerCase();

    // DETECT PLACE
    if (userText.includes("manali")) {
      setPlace("manali");
    } else if (userText.includes("goa")) {
      setPlace("goa");
    }

    const userMessage = { text: input, sender: "user" };
    setMessages((prev) => [...prev, userMessage]);

    try {
      const res = await fetch("http://localhost:5000/chat", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ message: input }),
      });

      const data = await res.json();

      setMessages((prev) => [
        ...prev,
        { text: data.reply, sender: "bot" },
      ]);
    } catch (err) {
      console.log(err);
    }

    setInput("");
  };

  // IMAGE LOGIC
  const getImage = () => {
    if (place === "manali") {
      return "https://source.unsplash.com/400x300/?manali,mountains";
    } else if (place === "goa") {
      return "https://source.unsplash.com/400x300/?goa,beach";
    } else {
      return "https://source.unsplash.com/400x300/?travel";
    }
  };

  return (
    <div className="app">

      <div className="header">🌍 AI Travel Assistant</div>

      <div className="main">

        {/* CHAT */}
        <div className="chat-container">
          <div className="chat-box">
            {messages.map((msg, index) => (
              <div key={index} className={`message ${msg.sender}`}>
                {msg.text}
              </div>
            ))}
            <div ref={chatEndRef} />
          </div>

          <div className="input-area">
            <input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask about places..."
            />
            <button onClick={sendMessage}>➤</button>
          </div>
        </div>

        {/* RIGHT PANEL WITH IMAGE */}
        <div className="info-panel">
          <h2>✈️ Travel Info</h2>

          <img
            src={getImage()}
            alt="place"
            className="place-img"
          />

          {place === "manali" && (
            <>
              <h3>🏔️ Manali</h3>
              <p>Best time: Oct–Feb</p>
              <p>Budget: ₹5k–₹15k</p>
            </>
          )}

          {place === "goa" && (
            <>
              <h3>🏝️ Goa</h3>
              <p>Best time: Nov–Feb</p>
              <p>Budget: ₹6k–₹20k</p>
            </>
          )}

        </div>

      </div>
    </div>
  );
}

export default App;
